/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWPedidoVendaDespacho-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PedCod.IsEmpty() AND &PedSts.IsEmpty() AND &PedCliCod.IsEmpty() AND &PedStsDsp.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Estoque") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = &PedSts.EnumerationDescription() WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 4, "Cliente") &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = &PedCliCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 6, "Despacho") If Not &PedStsDsp.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = &PedStsDsp.EnumerationDescription() Endif EndIf
If not (&PedTraSaiCod.IsEmpty() AND &PedTraSaiRaz.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cód.Trans.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedTraSaiCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Nome Trans.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(&PedTraSaiRaz) EndIf
If not (&PedDtaFat.IsEmpty() AND &PedDtaFat_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Faturado") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaFat WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "até") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaFat_To EndIf
If not (&LctTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Lançamento Tipo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &LctTip.EnumerationDescription() EndIf
If not (&LctAtuSal.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Atualiza Saldos") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &LctAtuSal.EnumerationDescription() EndIf
If not (&PedBlq.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Bloqueado Usuario") If Not &PedBlq.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PedBlq.EnumerationDescription() Endif EndIf
If not (&FilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo Lcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LctCod1 EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Vendedor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedVenCod1 EndIf Case &DynamicFiltersSelector1 = !'PEDDTAEMS' &PedDtaEms1.FromString(&GridStateDynamicFilter.Value) &PedDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEms1.IsEmpty() OR not &PedDtaEms_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaEms1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaEms_To1 EndIf Case &DynamicFiltersSelector1 = !'PEDDTADSP' &PedDtaDsp1.FromString(&GridStateDynamicFilter.Value) &PedDtaDsp_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaDsp1.IsEmpty() OR not &PedDtaDsp_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Despachado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaDsp1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaDsp_To1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo Lcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LctCod2 EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Vendedor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedVenCod2 EndIf Case &DynamicFiltersSelector2 = !'PEDDTAEMS' &PedDtaEms2.FromString(&GridStateDynamicFilter.Value) &PedDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEms2.IsEmpty() OR not &PedDtaEms_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaEms2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaEms_To2 EndIf Case &DynamicFiltersSelector2 = !'PEDDTADSP' &PedDtaDsp2.FromString(&GridStateDynamicFilter.Value) &PedDtaDsp_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaDsp2.IsEmpty() OR not &PedDtaDsp_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Despachado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaDsp2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaDsp_To2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo Lcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LctCod3 EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Vendedor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedVenCod3 EndIf Case &DynamicFiltersSelector3 = !'PEDDTAEMS' &PedDtaEms3.FromString(&GridStateDynamicFilter.Value) &PedDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEms3.IsEmpty() OR not &PedDtaEms_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaEms3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaEms_To3 EndIf Case &DynamicFiltersSelector3 = !'PEDDTADSP' &PedDtaDsp3.FromString(&GridStateDynamicFilter.Value) &PedDtaDsp_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaDsp3.IsEmpty() OR not &PedDtaDsp_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Despachado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaDsp3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaDsp_To3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Razão/Nome Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Crédito" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Faturado"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order PedDtaFat when &OrderedBy = 3 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 3 AND &OrderedDsc = True
using DSWWPedidoVendaDespacho(&PedCod, &PedSts, &PedCliCod, &PedStsDsp, &PedTraSaiCod, &PedTraSaiRaz , &PedDtaFat, &PedDtaFat_To, &LctTip, &LctAtuSal, &PedBlq, &FilCod , &DynamicFiltersSelector1, &LctCod1, &PedVenCod1, &PedDtaEms1, &PedDtaEms_To1, &PedDtaDsp1 , &PedDtaDsp_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &LctCod2, &PedVenCod2, &PedDtaEms2 , &PedDtaEms_To2, &PedDtaDsp2, &PedDtaDsp_To2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &LctCod3 , &PedVenCod3, &PedDtaEms3, &PedDtaEms_To3, &PedDtaDsp3, &PedDtaDsp_To3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = PedCod &gridPedCliCodRaz = iif(PedCliCodRaz.Length() > 30, Substr(PedCliCodRaz,1,30)+'...', PedCliCodRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&gridPedCliCodRaz)
&ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&NovoStatusFinanceiro)
&ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(&NovoStatus) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = PedDtaFat
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWPedidoVendaDespachoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWPedidoVendaDespachoGridState")) Else &GridState.FromXml(&Session.Get(!"WWPedidoVendaDespachoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSDSP" &PedStsDsp.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAICOD" &PedTraSaiCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAIRAZ" &PedTraSaiRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAFAT" &PedDtaFat.FromString(&GridStateFilterValue.Value) &PedDtaFat_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

